.[$FRAGMENT_CLASS$] {
  height: 680px;
  position: absolute;
  right: 0;
  top: -120px;
  width: 680px;
  z-index: 0;
}

.parallax-500 {
  animation: parallax-500;
  animation-range: 0% 100%;
  animation-timeline: scroll();
}

@keyframes parallax-500 {
  from {
    transform: translateY(0px);
  }
  to {
    transform: translateY(500px);
  }
}
